import java.util.*;
public class App {
    static <T extends Comparable<T>> T min(List<T> list) {
        if (list.isEmpty()) throw new IllegalArgumentException("Empty list");
        T result = list.get(0);
        for (T item : list) if (item.compareTo(result) < 0) result = item;
        return result;
    }
    public static void main(String[] args) {
        System.out.println(min(Arrays.asList(3, 1, 4, 1, 5)));
        System.out.println(min(Arrays.asList("Priya", "Aisha", "Raj")));
    }
}

import java.util.*;
public class App {
    static <T extends Number> double sum(List<T> numbers) {
        double total = 0;
        for (T n : numbers) total += n.doubleValue();
        return total;
    }
    public static void main(String[] args) {
        System.out.println(sum(Arrays.asList(10, 20, 30)));
        System.out.println(sum(Arrays.asList(1.5, 2.5, 3.5)));
        System.out.println(sum(Arrays.asList(100L, 200L, 300L)));
    }
}

import java.util.*;
public class App {
    static <T extends Comparable<T>> T clamp(T value, T min, T max) {
        if (value.compareTo(min) < 0) return min;
        if (value.compareTo(max) > 0) return max;
        return value;
    }
    public static void main(String[] args) {
        System.out.println(clamp(15, 0, 10));    // > max → max
        System.out.println(clamp(5,  0, 10));    // in range → unchanged
        System.out.println(clamp(-3, 0, 10));    // < min → min
        System.out.println(clamp("Priya", "Aisha", "Raj"));  // between → Priya
    }
}

import java.util.*;
class SortedBox<T extends Comparable<T>> {
    private List<T> items = new ArrayList<>();

    void add(T item) {
        items.add(item);
        Collections.sort(items);  // OK because T extends Comparable
    }
    T min() { return items.isEmpty() ? null : items.get(0); }
    T max() { return items.isEmpty() ? null : items.get(items.size()-1); }
    List<T> toList() { return Collections.unmodifiableList(items); }
}
public class App {
    public static void main(String[] args) {
        SortedBox<String> words = new SortedBox<>();
        words.add("Raj"); words.add("Aisha"); words.add("Priya");
        System.out.println(words.toList());
        System.out.println("Min: " + words.min() + " | Max: " + words.max());

        SortedBox<Integer> nums = new SortedBox<>();
        for (int n : new int[]{5,3,8,1,2}) nums.add(n);
        System.out.println(nums.toList());
    }
}

import java.util.*;
public class App {
    static <T extends Comparable<T>> boolean isBetween(T value, T low, T high) {
        return value.compareTo(low) >= 0 && value.compareTo(high) <= 0;
    }
    public static void main(String[] args) {
        System.out.println(isBetween(75, 60, 100));  // true
        System.out.println(isBetween(55, 60, 100));  // false
        System.out.println(isBetween("Raj", "Aisha", "Vikram")); // true (alphabetical)
        System.out.println(isBetween("Zara", "Aisha", "Vikram")); // false
    }
}

import java.util.*;
public class App {
    static <T extends Number> OptionalDouble average(List<T> nums) {
        if (nums.isEmpty()) return OptionalDouble.empty();
        double sum = 0;
        for (T n : nums) sum += n.doubleValue();
        return OptionalDouble.of(sum / nums.size());
    }
    public static void main(String[] args) {
        System.out.println(average(Arrays.asList(85, 92, 78, 95, 68, 88)).getAsDouble());
        System.out.println(average(Arrays.asList(1.5, 2.5, 3.5)).getAsDouble());
        System.out.println(average(new ArrayList<Integer>()));
    }
}

import java.util.*;
public class App {
    static <T extends Number & Comparable<T>> T median(List<T> list) {
        if (list.isEmpty()) throw new IllegalArgumentException("Empty list");
        List<T> sorted = new ArrayList<>(list);
        Collections.sort(sorted);  // uses Comparable
        return sorted.get(sorted.size() / 2);
    }
    public static void main(String[] args) {
        System.out.println(median(Arrays.asList(5, 1, 3, 4, 2)));         // [1,2,3,4,5] → 3
        System.out.println(median(Arrays.asList(1.5, 4.5, 3.5, 2.5)));   // [1.5,2.5,3.5,4.5] → 3.5
        System.out.println(median(Arrays.asList(500L, 100L, 300L)));      // [100,300,500] → 300
    }
}

class NumberBox<T extends Number> {
    private final T value;
    NumberBox(T v) { value = v; }
    T get()              { return value; }
    double doubleValue() { return value.doubleValue(); }
    long longValue()     { return value.longValue(); }
    boolean isPositive() { return value.doubleValue() > 0; }
    boolean isZero()     { return value.doubleValue() == 0; }
    double percentage(double total) { return (value.doubleValue() / total) * 100; }
    public String toString() { return "NumberBox(" + value + ")"; }
}
public class App {
    public static void main(String[] args) {
        NumberBox<Integer> ib = new NumberBox<>(42);
        NumberBox<Double>  db = new NumberBox<>(7.5);
        System.out.println("IntBox: " + ib.get() + " as double: " + ib.doubleValue() + " | positive: " + ib.isPositive());
        System.out.println("DblBox: " + db.get() + " as long: " + db.longValue() + " | positive: " + db.isPositive());
        System.out.println(ib.get() + " is " + ib.percentage(200) + "% of 200");
        System.out.println(db.get() + " is " + db.percentage(30) + "% of 30");
    }
}

import java.util.*;
class RangeUtils {
    static <T extends Comparable<T>> boolean overlaps(T aMin, T aMax, T bMin, T bMax) {
        // Ranges overlap if neither is entirely before the other
        return aMin.compareTo(bMax) <= 0 && bMin.compareTo(aMax) <= 0;
    }
    static <T extends Comparable<T>> List<T> sorted(List<T> list) {
        List<T> copy = new ArrayList<>(list);
        Collections.sort(copy);
        return copy;
    }
}
public class App {
    public static void main(String[] args) {
        System.out.println("Ranges [1,5] and [3,7] overlap: " + RangeUtils.overlaps(1, 5, 3, 7));
        System.out.println("Ranges [1,3] and [5,7] overlap: " + RangeUtils.overlaps(1, 3, 5, 7));
        List<String> names = Arrays.asList("Raj", "Aisha", "Vikram", "Priya");
        System.out.println("Sorted: " + RangeUtils.sorted(names));
    }
}

import java.util.*;
class Statistics<T extends Number & Comparable<T>> {
    private List<T> data = new ArrayList<>();
    void add(T v)        { data.add(v); }
    void addAll(List<T> l) { data.addAll(l); }
    int count()          { return data.size(); }
    double sum()         { double t=0; for (T n:data) t+=n.doubleValue(); return t; }
    double average()     { return data.isEmpty() ? 0 : sum()/count(); }
    T min() { T r=data.get(0); for (T n:data) if (n.compareTo(r)<0) r=n; return r; }
    T max() { T r=data.get(0); for (T n:data) if (n.compareTo(r)>0) r=n; return r; }
    double range()       { return max().doubleValue()-min().doubleValue(); }
    boolean isBetween(T v) { return v.compareTo(min())>=0 && v.compareTo(max())<=0; }
}
public class App {
    public static void main(String[] args) {
        Statistics<Integer> scores = new Statistics<>();
        scores.addAll(Arrays.asList(85, 92, 78, 95, 68, 88));
        System.out.printf("Count: %d, Sum: %.1f, Avg: %.2f%n",
            scores.count(), scores.sum(), scores.average());
        System.out.printf("Min: %d, Max: %d, Range: %.1f%n",
            scores.min(), scores.max(), scores.range());
        System.out.println("90 in range: " + scores.isBetween(90));

        Statistics<Double> prices = new Statistics<>();
        prices.addAll(Arrays.asList(2450.0, 3890.0, 1560.0, 412.0));
        System.out.println("Avg price: ₹" + prices.average());
    }
}

import java.util.*;
public class App {
    static <T extends Comparable<T>> int binarySearch(List<T> sorted, T target) {
        int low = 0, high = sorted.size() - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            int cmp = sorted.get(mid).compareTo(target);
            if (cmp == 0) return mid;
            if (cmp < 0)  low  = mid + 1;
            else          high = mid - 1;
        }
        return -1;
    }
    public static void main(String[] args) {
        List<Integer> nums = Arrays.asList(10, 20, 25, 35, 42, 56, 78);
        System.out.println("Index of 42: " + binarySearch(nums, 42));
        System.out.println("Index of 100: " + binarySearch(nums, 100));
        List<String> names = Arrays.asList("Aisha", "Raj", "Priya", "Vikram");
        Collections.sort(names);
        System.out.println("Index of Priya: " + binarySearch(names, "Priya"));
    }
}

import java.util.*;
class ComparableUtils {
    static <T extends Comparable<T>> T max(List<T> list) {
        T r = list.get(0); for (T t : list) if (t.compareTo(r) > 0) r = t; return r;
    }
    static <T extends Comparable<T>> T min(List<T> list) {
        T r = list.get(0); for (T t : list) if (t.compareTo(r) < 0) r = t; return r;
    }
    static <T extends Comparable<T>> T clamp(T v, T lo, T hi) {
        if (v.compareTo(lo) < 0) return lo;
        if (v.compareTo(hi) > 0) return hi;
        return v;
    }
    static <T extends Comparable<T>> List<T> sorted(List<T> list) {
        List<T> copy = new ArrayList<>(list);
        Collections.sort(copy);
        return copy;
    }
    static <T extends Number> double sum(List<T> nums) {
        double t = 0; for (T n : nums) t += n.doubleValue(); return t;
    }
    static <T extends Number & Comparable<T>> T medianOf(T a, T b, T c) {
        T big = a.compareTo(b) > 0 ? a : b;
        T mid = big.compareTo(c) > 0
            ? (a.compareTo(b) < 0 ? b : a).compareTo(c) < 0
                ? (a.compareTo(b) < 0 ? b : a) : c
            : big;
        // Simpler: sort all three
        List<T> three = new ArrayList<>(Arrays.asList(a, b, c));
        Collections.sort(three);
        return three.get(1);
    }
}
public class App {
    public static void main(String[] args) {
        List<Integer> scores = Arrays.asList(85, 92, 78, 95, 68, 88);
        System.out.println("Max: " + ComparableUtils.max(scores));
        System.out.println("Min: " + ComparableUtils.min(scores));
        System.out.println("Clamp 150 in [0,100]: " + ComparableUtils.clamp(150, 0, 100));
        System.out.println("Sorted: " + ComparableUtils.sorted(Arrays.asList("Raj","Aisha","Priya")));
        System.out.println("Sum: " + ComparableUtils.sum(scores));
        System.out.println("Median of 8,3,5: " + ComparableUtils.medianOf(8, 3, 5));
    }
}
